import { ChangeDetectorRef, Component, EventEmitter, Input, NgZone, Output, ViewChild } from '@angular/core';
import { first } from 'rxjs';
import {
    CloseReason,
    InputTranslation,
    InputType,
    InputValidationAttribute,
    InputValidator,
    NumberInputType,
    SelectedInput,
    SelectedType,
    TabInputData,
    TabInputInsertableModel,
    TabInputReturnData,
    TabInputValue,
    TabInputValueType,
    TabInputVariable,
    URValidatorFn,
    VirtualKeyboardLayout,
} from '@universal-robots/ui-models';
import { URPortalService } from '../../../services/ur-portal.service';
import { URFieldTriggerComponent } from '../FieldTrigger/ur-field-trigger.component';
import { URTabInputContainerComponent } from '../TabInputContainer/ur-tab-input-container.component';

@Component({
    selector: 'ur-tab-input',
    templateUrl: './ur-tab-input.component.html',
    styleUrls: ['./ur-tab-input.component.scss'],
    imports: [URFieldTriggerComponent],
})
export class URTabInputComponent {
    @ViewChild('triggerButton') triggerButton?: URFieldTriggerComponent;

    /**
     * override the default keyboard layout
     */
    @Input()
    keyboardLayout: VirtualKeyboardLayout = 'alpha-numeric';

    /**
     * whether the trigger is valid or not
     */
    @Input()
    valid = true;

    /**
     * to disable the field
     */
    @Input()
    disabled = false;

    /**
     * label to describe the field type (AKA dialog title)
     */
    @Input()
    label = '';

    /**
     * helper message to guide the user of the current state or purpose of the field
     */
    @Input()
    message = '';

    /**
     * placeholder for when no value
     */
    @Input()
    placeholder = '';

    /**
     * readonly attribute
     */
    @Input()
    readOnly = false;

    /**
     * disabled tabs - disable on of the SelectedInput (VALUE, VARIABLE or EXPRESSION)
     */
    @Input()
    disabledTabs: Array<SelectedType> = [];

    /**
     * list of validators to check input against
     *  A validator is a method that takes in an input string
     *  and returns an error message string if the input is not valid
     *  OR null if the input is valid.
     */
    @Input()
    validators: InputValidator[] | URValidatorFn[] = [];

    /**
     * Optional warning validator that evaluates warning conditions without invalidating the field
     */
    @Input()
    warningValidator?: URValidatorFn;

    /**
     * obj of native validation methods to check input against
     */
    @Input()
    validation: InputValidationAttribute = { required: false, type: false };

    /**
     * unit placeholder
     */
    @Input()
    unit = '';

    /**
     * Declaring how much the value increment or decrement
     */
    @Input()
    step = 10;

    /**
     * Controls if the input only allows positive numbers
     */
    @Input()
    positiveDigitsOnly = false;

    /**
     * translations
     */
    @Input()
    translations: InputTranslation = {};

    /**
     * type of input e.g. number, text, password
     */
    @Input()
    type: InputType | NumberInputType = 'text';

    /**
     * type of value of the input
     *  'string' | 'integer' | 'float'
     */
    @Input()
    valueType?: TabInputValueType | TabInputValueType[];

    /**
     * the value of the input
     * string | number | URVariable.
     * If URVariable, this property allows for updating the variable e.g. on rename
     */
    @Input()
    tabInputValue: TabInputValue = { selectedType: SelectedInput.VALUE, value: '' };

    /**
     * list of variables to be used in dropdown value select for the input.
     * The URVariable.valueType must be the same as provided in the input (valueType)
     * @deprecated using variables already available from the insertables property
     * thus this property is redundant and will be removed in future versions
     */
    @Input()
    variables: TabInputVariable[] = [];

    /**
     * list quick access items in expression editor
     */
    @Input()
    insertables?: TabInputInsertableModel;

    /**
     * Declaring the floating precision
     */
    @Input()
    precision = 10;

    /**
     * Optional additional text to append to input field label
     */
    @Input()
    inputLabel = '';

    /**
     * SI unit placeholder
     */
    @Input()
    siUnit = '';

    /**
     * set to true if new validation format is used (URValidatorFn)
     * @deprecated Temporary flag to explicitly specify validator format.
     * - true: All validators are URValidatorFn (new format)
     * - false/undefined: All validators are InputValidator (old format, default)
     *
     * This flag will be removed in the future once all validators are migrated to URValidatorFn.
     */
    @Input()
    useStandardValidators = false;

    /**
     * on input field clicked event listener
     */
    @Output()
    handleClick: EventEmitter<Event> = new EventEmitter();

    /**
     * on input field value change event listener
     */
    @Output()
    valueChanged: EventEmitter<TabInputValue> = new EventEmitter();

    /**
     * emits the valid change event
     * */
    @Output()
    validChanged: EventEmitter<boolean> = new EventEmitter();

    constructor(
        readonly dialogService: URPortalService,
        readonly cd: ChangeDetectorRef,
        private readonly ngZone: NgZone,
    ) {}

    getValid() {
        if (this.tabInputValue.selectedType === SelectedInput.VARIABLE) {
            const variables = this.variables.length > 0 ? this.variables : (this.insertables?.variables ?? []);
            const variable = variables.find((variable: TabInputVariable) => {
                let isCorrectValueType = false;
                if (Array.isArray(this.valueType)) {
                    isCorrectValueType = this.valueType.some((type) => type === variable.valueType);
                } else {
                    isCorrectValueType = this.valueType === variable.valueType;
                }

                return isCorrectValueType && variable.name === this.tabInputValue.value;
            });

            return this.valid && !!variable && !variable.suppressed;
        }
        return this.valid;
    }

    async onClick(event: Event) {
        event.preventDefault();
        this.handleClick.emit(event);
        const dialogData: TabInputData = {
            keyboardLayout: this.keyboardLayout,
            label: this.label,
            message: this.message,
            inputLabel: this.inputLabel,
            placeholder: this.placeholder,
            type: this.type,
            unit: this.unit,
            precision: this.precision,
            step: this.step,
            positiveDigitsOnly: this.positiveDigitsOnly,
            tabInputValue: { ...this.tabInputValue },
            validators: this.validators,
            warningValidator: this.warningValidator,
            useStandardValidators: this.useStandardValidators,
            validation: this.validation,
            valid: this.valid,
            valueType: this.valueType,
            variables: this.variables,
            insertables: this.insertables,
            translations: {
                ...this.translations,
            },
            tabs: (Object.keys(SelectedInput) as Array<SelectedType>).filter((tab) => !this.disabledTabs.includes(tab)),
        };
        if (!this.disabled && !this.readOnly) {
            const dialogRef = this.dialogService.open<TabInputReturnData>(URTabInputContainerComponent, dialogData);
            dialogRef.afterClose.pipe(first()).subscribe((result) => {
                if (result.reason === CloseReason.CONFIRMED && result.returnData !== undefined) {
                    const { selectedType, value, valid } = result.returnData;
                    this.valid = valid;

                    this.tabInputValue = { selectedType, value };
                    this.valueChanged.emit(this.tabInputValue);
                    this.validChanged.emit(valid);
                    this.ngZone.runOutsideAngular(() => {
                        requestAnimationFrame(() => {
                            this.triggerButton?.setFocus();
                        });
                    });
                }
            });
        }
    }

    unitToShow() {
        if (this.valueType !== 'string') {
            switch (this.tabInputValue.selectedType) {
                case SelectedInput.VALUE:
                    return this.unit;
                case SelectedInput.VARIABLE:
                case SelectedInput.EXPRESSION:
                    return this.siUnit;
                default:
                    return '';
            }
        }
        return '';
    }
}
