import { Component, input, linkedSignal, output } from '@angular/core';

/**
 * Presentational component for Input slider UI.
 */
@Component({
    selector: 'ur-slider',
    templateUrl: './ur-slider.component.html',
    styleUrls: ['./ur-slider.component.scss'],
    standalone: true,
    host: { '[style.--percentage]': "((value() - min()) / (max() - min()) * 100) + '%'" },
})
export class URSliderComponent {
    /**
     * percentage of the bar to fill - 1 through 100 - default 1
     */
    public readonly level = input(1);

    /**
     * steps to change the speed with - default = 1
     */
    public readonly step = input(1);

    /**
     * The lowest value in the range of permitted values.
     * Must be lower than the max value.
     * Default = 0
     */
    public readonly min = input(0);

    /**
     * The greatest value in the range of permitted values.
     * Must be greater than or equal to the value of the min value
     * Default = 100
     */
    public readonly max = input(100);

    /**
     * size of the speed container
     */
    public readonly width = input('100%');

    /**
     * to disable the bar
     */

    public readonly disabled = input(false);

    /**
     * function to call while the slider is moving
     */
    public readonly withLevelChange = output<Event>();

    /**
     * function to call after the slider has moved
     */
    public readonly afterLevelChange = output<Event>();

    /**
     * The current value of the slider.
     * Used to update the background fill percentage dynamically.
     */
    public readonly value = linkedSignal<number>(() => this.level());

    public valueChanged($event: Event) {
        this.afterLevelChange.emit($event);
    }

    public inputChanged($event: Event) {
        if ($event.target instanceof HTMLInputElement) {
            const value = Number($event.target.value);
            this.value.set(value);
        }
        this.withLevelChange.emit($event);
    }
}
