import { LowerCasePipe } from '@angular/common';
import {
    ChangeDetectionStrategy,
    Component,
    computed,
    ElementRef,
    HostListener,
    inject,
    OnInit,
    Output,
    signal,
    ViewChild,
} from '@angular/core';
import { AbstractControl } from '@angular/forms';
import { TranslateService, TranslateModule } from '@ngx-translate/core';
import { Key } from 'ts-key-enum';
import {
    CloseReason,
    CloseReasonType,
    DropdownOption,
    InputTranslation,
    InputValidator,
    SelectedInput,
    SelectedType,
    TabInputData,
    TabInputInsertableModel,
    TabInputReturnData,
    TabInputValue,
    TabInputValueType,
    TabInputVariable,
    URValidatorFn,
    VirtualKeyboardLayout,
} from '@universal-robots/ui-models';
import { DATA_TOKEN, DialogRef } from '../../../ref';
import { uniqueAlphaNumericId } from '../../../utils/uniqueAlphaNumericId';
import { URButtonComponent } from '../../Button/ur-button.component';
import { URGenericDialogComponent } from '../../Dialogs/GenericDialog/ur-generic-dialog.component';
import { URDropdownComponent } from '../../Dropdown/ur-dropdown.component';
import { URHeadingComponent } from '../../Heading/ur-heading.component';
import { URIconButtonComponent } from '../../IconButton/ur-icon-button.component';
import { URLabelComponent } from '../../Label/ur-label.component';
import { URTabComponent } from '../../Tab/ur-tab.component';
import { URTabsComponent } from '../../Tabs/ur-tabs.component';
import { URInputComponent } from '../Input/ur-input.component';
import { URNumberComponent } from '../NumberInput/ur-number-input.component';
import { URQuickAccessComponent } from './QuickAccess/ur-quick-access.component';
import { URUtilityButtonsComponent } from './UtilityButtons/ur-utility-buttons.component';

@Component({
    selector: 'ur-tab-input-container',
    templateUrl: './ur-tab-input-container.component.html',
    styleUrls: ['./ur-tab-input-container.component.scss'],
    changeDetection: ChangeDetectionStrategy.OnPush,
    imports: [
        URGenericDialogComponent,
        URLabelComponent,
        URTabsComponent,
        URTabComponent,
        URInputComponent,
        URNumberComponent,
        URDropdownComponent,
        LowerCasePipe,
        TranslateModule,
        URHeadingComponent,
        URIconButtonComponent,
        URButtonComponent,
        URQuickAccessComponent,
        URUtilityButtonsComponent,
    ],
})
export class URTabInputContainerComponent implements OnInit {
    // Injected dependencies
    readonly data = inject<TabInputData>(DATA_TOKEN);
    protected readonly translate = inject(TranslateService);
    protected readonly element = inject(ElementRef);
    private readonly dialogRef = inject<DialogRef<TabInputReturnData>>(DialogRef);

    @ViewChild('textInput') textInput?: URInputComponent;
    @ViewChild('numberInput') numberInput?: URNumberComponent;
    @ViewChild('expressionInput') expressionInput?: URInputComponent;

    readonly CloseReason = CloseReason;
    readonly uid = uniqueAlphaNumericId();
    previousValue: TabInputValue = { ...this.data.tabInputValue };

    // Signals
    selectedType = signal<SelectedType>(this.data.tabInputValue.selectedType ?? SelectedInput.VALUE);
    inputValue = signal<string | number>('');
    expressionValue = signal<string | number>('');
    variableNameList = signal<DropdownOption[]>([]);
    variableValue = signal<DropdownOption | undefined>(undefined);
    valueValid = signal<boolean>(true);
    keyboardLayout = signal<VirtualKeyboardLayout>(this.data.keyboardLayout ?? 'alpha-numeric');
    validators = signal<URValidatorFn[]>([]);
    constructor() {
        this.expressionTranslations = {
            requiredValidationMessage: this.translate.instant('ui.validation.tab_input.required'),
            tooLongMessage: this.translate.instant('ui.validation.tab_input.max_length'),
        };

        // Convert validators based on useStandardValidators flag
        // for now only for number validators
        if (this.data.validators && this.data.useStandardValidators !== undefined) {
            this.validators.set(this.convertValidators(this.data.validators, this.data.useStandardValidators));
        }

        if (this.data.tabs.length === 1) {
            this.data.tabInputValue.selectedType = this.data.tabs[0];
            this.selectedType.set(this.data.tabs[0]);
        }

        this.variableNameList.set(this.getVariableNameList());
        this.insertable = this.data.insertables;
        this.generateMessage();
    }

    private getKeyboardLayout = (valueType: TabInputValueType): VirtualKeyboardLayout => {
        if (valueType === 'integer') {
            return 'numeric-fixed';
        } else if (valueType === 'float') {
            return 'numeric-free';
        } else {
            return this.data.keyboardLayout ?? 'alpha-numeric';
        }
    };

    /**
     * Converts validators to the appropriate format based on the flag.
     * This is done once at initialization for better performance.
     *
     * @param validators - Array of validators
     * @param useStandardValidators - Flag indicating validator format
     * @returns Converted validators (all as URValidatorFn)
     */
    private convertValidators(validators: (InputValidator | URValidatorFn)[], useStandardValidators: boolean): URValidatorFn[] {
        if (!Array.isArray(validators)) {
            return validators;
        }
        if (useStandardValidators) {
            // Validators are already URValidatorFn, return as-is
            return validators as URValidatorFn[];
        } else {
            // Validators are InputValidator, convert to URValidatorFn
            return validators.map((validator) => (control: AbstractControl) => (validator as InputValidator)(control.value));
        }
    }

    /**
     * Runs a validator.
     * If useStandardValidators flag was set, validators are already converted in constructor.
     * Otherwise, uses unreliable automatic detection.
     *
     * @param validator - InputValidator or URValidatorFn
     * @param control - The form control to validate
     */

    // UI state
    valueInfo = '';
    expressionInfo = '';
    placeholder?: string;
    expressionTranslations?: InputTranslation;
    insertable?: TabInputInsertableModel;

    isValid = computed(() => {
        const type = this.selectedType();

        if (type === SelectedInput.VALUE) {
            return this.valueValid();
        }

        if (type === SelectedInput.VARIABLE) {
            return this.variableValid(this.variableValue()?.label);
        }

        if (type === SelectedInput.EXPRESSION) {
            return this.expressionValue() !== '';
        }

        return true;
    });

    @Output()
    @HostListener('document:keydown', ['$event'])
    onKeydownHandler(event: KeyboardEvent) {
        if (this.element.nativeElement.matches(':focus-within')) {
            event.stopPropagation();
            event.stopImmediatePropagation();

            const changesMade = this.currentValue() !== this.previousValue?.value;
            const validChange = this.isValid();

            // On Enter close dialog with current value saved
            if (event.key === Key.Enter && changesMade && validChange) {
                this.onDialogClose({ $event: event, reason: CloseReason.CONFIRMED });
            }
        }
    }

    ngOnInit(): void {
        this.placeholder = `${this.previousValue.selectedType}: ${this.previousValue.value ?? ''}`;
        this.setInitialValues();
    }

    private setInitialValues(): void {
        const { selectedType, value } = this.previousValue;
        // set initial values based on selected type
        switch (selectedType) {
            case SelectedInput.VALUE:
                this.inputValue.set(value ?? 0);
                break;
            case SelectedInput.VARIABLE:
                if (value !== undefined) {
                    this.variableValue.set(
                        this.variableNameList().find((variable) => variable.label === value.toString()) ??
                            ({ label: value.toString(), invalid: true } as DropdownOption),
                    );
                }
                break;
            case SelectedInput.EXPRESSION:
                this.expressionValue.set(value ?? '');
                break;
            default:
                this.inputValue.set(0);
        }
        // keyboard layout
        this.keyboardLayout.set(this.getKeyboardLayout(this.data.valueType as TabInputValueType));
    }

    private generateMessage(): void {
        const currentValue = this.translate.instant('app.current_value', { value: this.previousValue.value });

        switch (this.previousValue.selectedType) {
            case SelectedInput.VALUE:
                this.valueInfo = currentValue;
                break;
            case SelectedInput.EXPRESSION:
                this.expressionInfo = currentValue;
                break;
        }
    }

    currentInput(): URInputComponent | URNumberComponent | undefined {
        switch (this.selectedType()) {
            case SelectedInput.VALUE:
                return this.data.valueType === 'string' ? this.textInput : this.numberInput;
            case SelectedInput.EXPRESSION:
                return this.expressionInput;
            default:
                return undefined;
        }
    }

    currentValue() {
        switch (this.selectedType()) {
            case SelectedInput.VALUE:
                return this.inputValue();
            case SelectedInput.EXPRESSION:
                return this.expressionValue();
            case SelectedInput.VARIABLE:
                return this.variableValue()?.label;
            default:
                return this.previousValue.value;
        }
    }

    onDialogClose({ reason }: { $event?: Event | KeyboardEvent; reason: CloseReasonType }) {
        if (reason === CloseReason.CONFIRMED) {
            const returnValue: TabInputValue = {
                value: this.currentValue() ?? '',
                selectedType: this.selectedType(),
            };
            this.data.tabInputValue = returnValue;
            this.dialogRef.close({
                reason: CloseReason.CONFIRMED,
                returnData: {
                    ...returnValue,
                    valid: this.isValid(),
                },
            });
        } else if (reason === CloseReason.CANCELLED) {
            this.dialogRef.close({ reason });
        }
    }

    onVariableSelect = (variableName: string) => this.expressionAdded(variableName);
    onFunctionSelected = (functionName: string) => this.expressionAdded(functionName);
    onBuiltInSelected = (builtInName: string) => this.expressionAdded(builtInName);
    onQuickAccessSelected = (name: string) => this.expressionAdded(name);

    private getVariables(): TabInputVariable[] | undefined {
        // The variable property is deprecated, so first check if variables are provided there
        // this can be removed when the property is fully removed
        return this.data?.variables?.length ? this.data.variables : this.data.insertables?.variables;
    }

    variableValid(variableName: string | undefined): boolean {
        const variables = this.getVariables();
        if (!variableName || !variables) {
            return false;
        }
        const variable = variables.find((v) => v.name === variableName);
        return !!variable && !variable.suppressed;
    }

    public getVariableNameList(): DropdownOption[] {
        const variables = this.getVariables();
        if (!variables) {
            return [];
        }

        return variables
            .filter((varObj) =>
                Array.isArray(this.data.valueType)
                    ? this.data.valueType.some((valType) => valType === varObj.valueType)
                    : this.data.valueType === varObj.valueType,
            )
            .map((item) => ({ label: item.name, invalid: !!item.suppressed }));
    }

    public getLabel(key: string): string {
        const label = this.translate.instant(key);
        return this.data.inputLabel ? `${label} (${this.data.inputLabel})` : label;
    }

    onValidChanged = (valid: boolean) => this.valueValid.set(valid);

    assertSpaceBefore(utilityExpression: string, start: number): string {
        const expressionAsString = this.expressionValue().toString();
        if (start === 0 || expressionAsString[start - 1] === ' ') {
            return utilityExpression.trimStart();
        }
        return utilityExpression;
    }

    assertSpaceAfter(utilityExpression: string, end: number): string {
        const expressionAsString = this.expressionValue().toString();
        if (expressionAsString[end] === ' ') {
            return utilityExpression.trimEnd();
        }
        return utilityExpression;
    }

    expressionAdded(utilityExpression: string): void {
        const { start, end } = this.expressionInput?.getCursorPosition() ?? { start: 0, end: 0 };
        const expressionAsString = this.expressionValue().toString();

        const trimmedExpression = this.assertSpaceAfter(this.assertSpaceBefore(utilityExpression, start), end);

        const newValue = expressionAsString.substring(0, start) + trimmedExpression + expressionAsString.substring(end);

        this.expressionValue.set(newValue);

        requestAnimationFrame(() => {
            this.expressionInput?.setCursorPosition(trimmedExpression, start);
            this.expressionInput?.checkValidators?.();
        });
    }
}
