import { NgClass } from '@angular/common';
import {
    ChangeDetectionStrategy,
    Component,
    input,
    linkedSignal,
    model,
    OnChanges,
    output,
    SimpleChanges,
    ViewEncapsulation,
} from '@angular/core';
import { URIconComponent } from '../Icon/ur-icon.component';

@Component({
    selector: 'ur-tab',
    templateUrl: './ur-tab.component.html',
    styleUrls: ['./ur-tab.scss'],
    encapsulation: ViewEncapsulation.None,
    changeDetection: ChangeDetectionStrategy.OnPush,
    imports: [NgClass, URIconComponent],
})
export class URTabComponent implements OnChanges {
    activeLink = model<string>('');

    /**
     * title text
     */
    title = input<string>();

    iconPosition = input<'column' | 'row'>('column');

    /**
     * subtitle text (only shown if tabs are vertical)
     */
    subtitle = input<string>();

    /**
     * is this tab disabled
     */
    disabled = input(false);

    valid = input(true);

    /**
     * navigation link for this tab
     */
    link = input<string>();
    isActive = linkedSignal(() => {
        return this.activeLink().toLowerCase() === this.link()?.toLowerCase();
    });
    icon = input<string>();

    /**
     * click event listener
     */
    clicked = output<string | undefined>();

    /**
     * listener to check for title or link changing
     */
    inputsChanged = output<SimpleChanges>();

    ngOnChanges(changes: SimpleChanges) {
        this.inputsChanged.emit(changes);
    }
    public setActiveState(isActive: boolean) {
        this.isActive.set(isActive);
    }
}
