import { ChangeDetectionStrategy, Component, computed, input, InputSignal, output, signal, ViewEncapsulation } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { TranslateModule } from '@ngx-translate/core';
import { ValidationChangeEvent } from '@universal-robots/ui-models';
import { URHelperMessageComponent } from '../../HelperMessage/ur-helper-message.component';
import { URIconComponent } from '../../Icon/ur-icon.component';
import { URLabelComponent } from '../../Label/ur-label.component';
import { URField } from '../ur-field';

@Component({
    selector: 'ur-time',
    templateUrl: './ur-time.component.html',
    styleUrls: ['./ur-time.component.scss'],
    encapsulation: ViewEncapsulation.None,
    changeDetection: ChangeDetectionStrategy.OnPush,
    imports: [URIconComponent, URLabelComponent, FormsModule, URHelperMessageComponent, TranslateModule],
    standalone: true,
})
export class URTimeComponent extends URField {
    validationChanged = output<ValidationChangeEvent>();
    valueChange = output<string>();

    /**
     * When used with time inputs, `min` specifies the earliest time that can be selected.
     */
    min = input<number>();

    /**
     * When used with date inputs, `max` specifies the latest time the user can select.
     */
    max = input<number>();

    /**
     * Defines the time precision (in seconds) for the time input.
     *
     * This value is applied to the `step` attribute of `<input type="time">`.
     *
     * - Use `1` to allow seconds (e.g. 12:30:45)
     * - Use `60` to allow minutes only (e.g. 12:30, 12:31)
     * ```
     */
    sec: InputSignal<number | undefined> = input<number>();

    /**
     * When set to `true`, indicates that the input field must have a value for the form to be considered valid.
     * Defaults to `false`.
     */
    required = input(false);

    /** When true, format hint shows 12-hour otherwise 24-hour (local) */
    isTeachPendant = input(false);

    validationMessage = signal<string | null>(null);
    readonly isInvalid = computed(() => this.validationMessage() !== null);

    onInput(event: Event): void {
        const inputEl = event.target as HTMLInputElement;
        this.validateTimeInput(inputEl.value);

        if (this.validationMessage() !== null) {
            return;
        }

        if (inputEl.value) {
            this.value = inputEl.value;
            this.valueChange.emit(inputEl.value);
            // When user types invalid minutes/seconds (e.g. 99), browser auto-corrects to 59 but display lags.
            const parts = inputEl.value.split(':');
            const lastSegment = Number(parts[parts.length - 1]);
            if (lastSegment === 59) {
                inputEl.blur();
            }
        }
    }

    private validateTimeInput(value: string): void {
        if (!value) {
            if (this.required()) {
                this.setInvalid(this.translate.instant('ui.validation.invalid'));
            } else {
                this.setValid();
            }
            return;
        }
        const parts = value.split(':');
        const expectsSeconds = this.sec() === 1;
        if (expectsSeconds && parts.length !== 3) {
            this.setInvalid(this.translate.instant('ui.validation.invalid'));
        } else {
            this.setValid();
        }
    }

    private setInvalid(message: string | null): void {
        this.validationMessage.set(message);
        this.validationChanged.emit({ status: 'INVALID' });
    }

    private setValid(): void {
        this.validationMessage.set(null);
        this.validationChanged.emit({ status: 'VALID' });
    }
}
