import { ChangeDetectionStrategy, Component, ElementRef, HostBinding, Input, ViewEncapsulation } from '@angular/core';
import { IconSize } from '../../models/ur-icon.model';

@Component({
    selector: 'ur-icon',
    templateUrl: './ur-icon.component.html',
    styleUrls: ['./ur-icon.component.scss'],
    encapsulation: ViewEncapsulation.None,
    changeDetection: ChangeDetectionStrategy.OnPush,
    standalone: true,
})
export class URIconComponent {
    /**
     * An icon name (check list of built-in icons in ../font-icons.scss for icon names), e.g. 'script', 'application', etc.
     * Or custom/external icon markup.
     */
    @Input()
    set icon(value: string) {
        if (!value) {
            return;
        }

        // External icon markup:
        if (/[<>]/.test(value)) {
            this.element.nativeElement.innerHTML = value;
            return;
        }

        // Built-in icon by name:
        this.iconName = value;
    }

    public iconName = 'access';

    /**
     * Optional badge icon name
     */
    @Input() badgeIcon: string | undefined;

    /**
     * Controls visibility of the badge icon
     */
    @Input() badgeVisible = false;

    /**
     * Label text
     */
    @Input()
    size: IconSize = 'small';
    @HostBinding('class') get className() {
        return `ur-icon ur-${this.iconName}-icon ur-icon-${this.size}`;
    }
    constructor(private readonly element: ElementRef) {}
}
