import { ChangeDetectionStrategy, Component, computed, input, output, signal, ViewEncapsulation } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { TranslateModule } from '@ngx-translate/core';
import { ValidationChangeEvent } from '@universal-robots/ui-models';
import { URHelperMessageComponent } from '../../HelperMessage/ur-helper-message.component';
import { URIconComponent } from '../../Icon/ur-icon.component';
import { URLabelComponent } from '../../Label/ur-label.component';
import { URField } from '../ur-field';

@Component({
    selector: 'ur-date',
    templateUrl: './ur-date.component.html',
    styleUrls: ['./ur-date.component.scss'],
    encapsulation: ViewEncapsulation.None,
    changeDetection: ChangeDetectionStrategy.OnPush,
    imports: [FormsModule, URLabelComponent, URIconComponent, URHelperMessageComponent, TranslateModule],
    standalone: true,
})
export class URDateComponent extends URField {
    validationChanged = output<ValidationChangeEvent>();
    valueChange = output<Date>();
    required = input(false);

    /** When true, format hint shows mm/dd/yy (teach pendant) otherwise dd/mm/yyyy (local) */
    isTeachPendant = input(false);

    /** Minimum allowed year. Defaults to current year - 70. */
    minYear = input<number | undefined>(undefined);

    /** Maximum allowed year. Defaults to 2037 (last year before Y2038 overflow). */
    maxYear = input<number | undefined>(undefined);

    /** Max year enforced for Fast-DDS Y2038 (RTPS Time_t int32 limit; overflow on 19 Jan 2038). @see https://github.com/ros2/rcl_interfaces/issues/85 */
    private static readonly MAX_YEAR = 2037;

    /** Params for year range error message when year is outside min/max. Null when valid. */
    yearRangeError = signal<{ minYear: number; maxYear: number } | null>(null);

    /** Validation message to display when invalid (empty, partial, or year out of range). Null when valid. */
    validationMessage = signal<string | null>(null);

    readonly isInvalid = computed(() => this.validationMessage() !== null);

    get minDate(): string {
        const y = this.minYear() ?? new Date().getFullYear() - 70;
        return `${y}-01-01`;
    }

    get maxDate(): string {
        const y = Math.min(this.maxYear() ?? URDateComponent.MAX_YEAR, URDateComponent.MAX_YEAR);
        return `${y}-12-31`;
    }

    onInput(event: Event) {
        const input = event.target as HTMLInputElement;
        if (!input.value) {
            this.setInvalid(this.required() ? this.translate.instant('ui.validation.invalid') : null);
            return;
        }

        this.value = input.value;

        const result = this.parseAndValidateDate(input.value);
        if (result && 'date' in result) {
            this.valueChange.emit(result.date);
            this.setValid();
        } else if (result && 'yearRange' in result) {
            this.setInvalidYearRange(result.yearRange);
        } else {
            this.setInvalid(this.required() ? this.translate.instant('ui.validation.invalid') : null);
        }
    }

    private parseAndValidateDate(value: string): { date: Date } | { yearRange: { minYear: number; maxYear: number } } | null {
        const validDatePattern = /^\d{4}-\d{2}-\d{2}$/;
        if (!validDatePattern.test(value)) {
            return null;
        }
        const parts = value.split('-');
        const y = parseInt(parts[0] ?? '', 10);
        const m = parseInt(parts[1] ?? '', 10) - 1;
        const d = parseInt(parts[2] ?? '', 10);

        const thisYear = new Date().getFullYear();
        const minY = this.minYear() ?? thisYear - 70;
        const maxY = Math.min(this.maxYear() ?? URDateComponent.MAX_YEAR, URDateComponent.MAX_YEAR);
        if (y < minY || y > maxY) {
            return { yearRange: { minYear: minY, maxYear: maxY } };
        }

        const dateObj = new Date(y, m, d);
        return Number.isNaN(dateObj.getTime()) ? null : { date: dateObj };
    }

    private setInvalid(message: string | null): void {
        this.yearRangeError.set(null);
        this.validationMessage.set(message);
        this.validationChanged.emit({ status: 'INVALID' });
    }

    private setInvalidYearRange(range: { minYear: number; maxYear: number }): void {
        this.yearRangeError.set(range);
        this.validationMessage.set(this.translate.instant('ui.validation.yearRange', range));
        this.validationChanged.emit({ status: 'INVALID', errors: { yearRange: range } });
    }

    private setValid(): void {
        this.yearRangeError.set(null);
        this.validationMessage.set(null);
        this.validationChanged.emit({ status: 'VALID' });
    }
}
